"use strict";async function t(t,n={}){const e=await fetch(`http://localhost:3000/api/v1${t}`,{...n,headers:{"Content-Type":"application/json",...n.headers}}),o=await e.json();if(200!==o.code&&void 0!==o.code)throw new Error(o.message||"请求失败");return o.data||o}exports.del=async function(n){return t(n,{method:"DELETE"})},exports.get=async function(n){return t(n,{method:"GET"})},exports.post=async function(n,e){return t(n,{method:"POST",body:JSON.stringify(e)})},exports.put=async function(n,e){return t(n,{method:"PUT",body:JSON.stringify(e)})};
